import java.util.List;
import java.util.stream.Collectors;

public class Query {
    public List<String> process(List<Integer> numbers) {
        return numbers.stream()
                      .filter(n -> n > 10)
                      .map(Object::toString)
                      .collect(Collectors.toList());
    }
}

